import type { Metadata } from "next"
import LeaseContract from "./LeaseContract"

export const metadata: Metadata = {
  title: "賃貸借契約書 / 重要事項説明 | ぐんじょう賃貸管理",
  description:
    "宅地建物取引士・賃貸仲介担当が住宅の賃貸借契約を準備・説明・締結する画面。物件/契約ヘッダ（物件名・所在・部屋番号・間取り・契約種別・契約日・入居予定日）の上で、契約条件（賃料・管理費・敷金・礼金・契約期間・更新・支払方法）を整え、特約事項（ペット不可・楽器・原状回復・短期解約違約金）を追加/削除/並べ替えで編集し、法令上必須の重要事項説明（登記・権利関係 / 法令上の制限 / インフラ / 解除事由 / 敷金精算 / 宅建士の記名）を構造化して説明・確認する。借主は重説の受領を確認し、宅建士と借主が相互確認（2人確認）する。当事者（貸主・借主・連帯保証人/家賃保証会社・宅建業者/宅建士）の記名押印・署名を記録し、契約締結すると契約内容はロック（読み取り専用）され、締結者と日時を記録する。締結後の変更は覚書（追記：当事者・締結日つき）でのみ行える、契約準備・締結のための法的文書画面。",
}

export default function LeaseContractPage() {
  return <LeaseContract />
}

// Seed data + domain types for the 賃貸借契約 / 重要事項説明 screen.
// All money is whole-yen (JPY). No external state — the screen is self-contained.

export type ContractKind = "普通借家" | "定期借家"
export type RenewalKind = "自動更新" | "合意更新" | "更新なし（定期）"
export type PartyRole = "貸主" | "借主" | "連帯保証人" | "宅建業者・宅建士"

export interface PropertyHeader {
  propertyName: string
  address: string
  roomNumber: string
  layout: string // 間取り e.g. 1LDK
  area: string // 専有面積 e.g. 42.5㎡
  kind: ContractKind
  contractDate: string // YYYY-MM-DD
  moveInDate: string // 入居予定日 YYYY-MM-DD
}

export interface ContractTerms {
  rent: number // 賃料 / 月
  managementFee: number // 管理費・共益費 / 月
  deposit: number // 敷金
  keyMoney: number // 礼金
  termStart: string // 契約期間 開始 YYYY-MM-DD
  termEnd: string // 契約期間 満了 YYYY-MM-DD
  renewalKind: RenewalKind
  renewalFee: number // 更新料
  paymentMethod: string // 支払方法
  paymentDay: string // 支払日 e.g. 毎月末日
}

export interface SpecialClause {
  id: string
  text: string
}

export interface DisclosureItem {
  id: string
  /** 重要事項説明の項目名 */
  title: string
  /** 説明内容 */
  detail: string
  /** 宅建士が説明済みとして確認したか */
  confirmed: boolean
}

export interface Party {
  id: string
  role: PartyRole
  name: string
  detail: string // 住所・免許番号・保証会社名 など
  /** required parties must sign before the contract can be executed */
  required: boolean
  /** ISO timestamp the party signed / 記名押印 — undefined = unsigned */
  signedAt?: string
}

let clauseSeq = 0
const clause = (text: string): SpecialClause => ({ id: `clause-${clauseSeq++}`, text })

