/** 宅建士のID — SignedRecord の signerId / primary executor として記録する。 */
export const TAKKEN_SHI_ID = "佐野 真央（宅建士 第123456号）"

/** 借主のID — 重説の相互確認（CoSign）で「受領した借主」として記録する。 */
export const LESSEE_ID = "山田 花子（借主）"

export function formatDateJa(iso: string): string {
  const m = /^(\d{4})-(\d{2})-(\d{2})/.exec(iso)
  if (!m) return iso
  return `${m[1]}年${Number(m[2])}月${Number(m[3])}日`
}

export function formatTimestampJa(iso: string): string {
  const d = new Date(iso)
  if (Number.isNaN(d.getTime())) return iso
  const p = (n: number) => String(n).padStart(2, "0")
  return `${d.getFullYear()}/${p(d.getMonth() + 1)}/${p(d.getDate())} ${p(d.getHours())}:${p(d.getMinutes())}`
}

/** 契約期間（月数）— サマリ用。 */
export function monthsBetween(startIso: string, endIso: string): number | null {
  const s = new Date(startIso)
  const e = new Date(endIso)
  if (Number.isNaN(s.getTime()) || Number.isNaN(e.getTime())) return null
  const months = (e.getFullYear() - s.getFullYear()) * 12 + (e.getMonth() - s.getMonth())
  return months > 0 ? months : null
}

"use client"

import * as React from "react"
import {
  IconBuildingSkyscraper,
  IconFileText,
  IconShieldCheck,
  IconUsers,
  IconArrowUp,
  IconArrowDown,
  IconTrash,
  IconPlus,
  IconPrinter,
  IconDeviceFloppy,
  IconRubberStamp,
  IconCircleCheck,
  IconAlertTriangle,
} from "@tabler/icons-react"

import {
  Card,
  CardHeader,
  CardTitle,
  CardDescription,
  CardContent,
  Badge,
  Button,
  Input,
  Textarea,
  Select,
  Checkbox,
  CurrencyInput,
  MetadataList,
  Separator,
  Table,
  TableHeader,
  TableBody,
  TableRow,
  TableHead,
  TableCell,
  Tabs,
  TabsList,
  TabsTrigger,
  TabsContent,
  Alert,
  AlertTitle,
  AlertDescription,
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
  DialogClose,
  SignedRecord,
  type SignedRecordValue,
  CoSign,
  CoSignBadge,
  type CoSignValue,
  formatCurrency,
} from "@gunjo/ui"

import {
  initialHeader,
  initialTerms,
  initialClauses,
  initialDisclosures,
  initialParties,
  TAKKEN_SHI_ID,
  formatDateJa,
  formatTimestampJa,
  monthsBetween,
  type ContractTerms,
  type SpecialClause,
  type DisclosureItem,
  type Party,
  type ContractKind,
  type RenewalKind,
} from "./data"

const yen = (n: number) => formatCurrency(n, { currency: "JPY", locale: "ja-JP" })

let clauseSeq = 1000
const newClauseId = () => `clause-${clauseSeq++}`

export default function LeaseContract() {
  // --- contract draft state ------------------------------------------------
  const [header, setHeader] = React.useState(initialHeader)
  const [terms, setTerms] = React.useState<ContractTerms>(initialTerms)
  const [clauses, setClauses] = React.useState<SpecialClause[]>(initialClauses)
  const [disclosures, setDisclosures] = React.useState<DisclosureItem[]>(initialDisclosures)
  const [parties, setParties] = React.useState<Party[]>(initialParties)

  // 借主が「重要事項説明を受領した」ことの確認（attestation）
  const [lesseeAcknowledged, setLesseeAcknowledged] = React.useState(false)
  // 宅建士 ↔ 借主 の重説 相互確認（2人確認） — CoSign が genuinely 2-party なのでここで使う
  const [reiSetsuCoSign, setReiSetsuCoSign] = React.useState<CoSignValue | undefined>(undefined)

  // SignedRecord — execute → lock → 覚書(addendum) のエンジン
  const [record, setRecord] = React.useState<SignedRecordValue>({
    status: "draft",
    addenda: [],
  })
  const executed = record.status === "signed"

  // sign-confirm dialog
  const [confirmOpen, setConfirmOpen] = React.useState(false)
  // toast-ish inline notice for 下書き保存
  const [savedAt, setSavedAt] = React.useState<string | null>(null)

  // SignedRecord's onChange is the single source of truth for the record. We
  // intercept the draft→signed transition to also stamp every required party's
  // 記名押印 timestamp (SignedRecord records only ONE signedBy — see FINDINGS).
  const handleRecordChange = (next: SignedRecordValue) => {
    const becameSigned = record.status !== "signed" && next.status === "signed"
    if (becameSigned) {
      setParties((p) =>
        p.map((x) => (x.required && !x.signedAt ? { ...x, signedAt: next.signedAt ?? new Date().toISOString() } : x))
      )
    }
    setRecord(next)
  }

  // --- derived: validation for execution -----------------------------------
  const requiredTermsFilled =
    terms.rent > 0 &&
    terms.deposit >= 0 &&
    Boolean(terms.termStart) &&
    Boolean(terms.termEnd) &&
    Boolean(header.propertyName) &&
    Boolean(header.contractDate)

  const allDisclosuresConfirmed = disclosures.every((d) => d.confirmed)
  const reiSetsuDone = allDisclosuresConfirmed && lesseeAcknowledged && Boolean(reiSetsuCoSign)

  const requiredParties = parties.filter((p) => p.required)
  // 締結前のチェックでは「当事者が存在し名前が入っている」ことを要件にする。
  // 個々の記名押印は締結プロセスの一部として締結時に確定する。
  const requiredPartiesPresent = requiredParties.every((p) => p.name.trim().length > 0)

  const missing: string[] = []
  if (!requiredTermsFilled) missing.push("契約条件（賃料・敷金・契約期間・契約日）")
  if (!allDisclosuresConfirmed) missing.push("重要事項説明の全項目の確認")
  if (!lesseeAcknowledged) missing.push("借主による重説受領の確認")
  if (!reiSetsuCoSign) missing.push("宅建士・借主による重説の相互確認（2人確認）")
  if (!requiredPartiesPresent) missing.push("必須当事者（貸主・借主・連帯保証人・宅建士）")

  const canExecute = missing.length === 0

  // --- derived: money reconciliation ---------------------------------------
  const monthlyTotal = terms.rent + terms.managementFee
  // 契約時初期費用 = 敷金 + 礼金 + 初月賃料(管理費込) + 仲介手数料(賃料1ヶ月+税)
  const brokerFee = Math.round(terms.rent * 1.1)
  const initialCost = terms.deposit + terms.keyMoney + monthlyTotal + brokerFee
  const months = monthsBetween(terms.termStart, terms.termEnd)

  // --- handlers ------------------------------------------------------------
  const updateTerm = <K extends keyof ContractTerms>(key: K, value: ContractTerms[K]) =>
    setTerms((t) => ({ ...t, [key]: value }))

  const saveDraft = () => setSavedAt(new Date().toISOString())

  // clause ops
  const addClause = () => setClauses((c) => [...c, { id: newClauseId(), text: "" }])
  const removeClause = (id: string) => setClauses((c) => c.filter((x) => x.id !== id))
  const updateClause = (id: string, text: string) =>
    setClauses((c) => c.map((x) => (x.id === id ? { ...x, text } : x)))
  const moveClause = (id: string, dir: -1 | 1) =>
    setClauses((c) => {
      const i = c.findIndex((x) => x.id === id)
      const j = i + dir
      if (i < 0 || j < 0 || j >= c.length) return c
      const next = c.slice()
      ;[next[i], next[j]] = [next[j], next[i]]
      return next
    })

  // disclosure confirm
  const toggleDisclosure = (id: string, on: boolean) =>
    setDisclosures((d) => d.map((x) => (x.id === id ? { ...x, confirmed: on } : x)))

  // per-party signature / 記名押印 (multi-party — hand-rolled; no primitive)
  const signParty = (id: string) =>
    setParties((p) => p.map((x) => (x.id === id ? { ...x, signedAt: new Date().toISOString() } : x)))

  // --- status badge --------------------------------------------------------
  const statusBadge = executed ? (
    <Badge variant="success">締結済</Badge>
  ) : reiSetsuDone ? (
    <Badge variant="warning">締結待ち</Badge>
  ) : lesseeAcknowledged || reiSetsuCoSign || disclosures.some((d) => d.confirmed) ? (
    <Badge variant="warning">重説待ち</Badge>
  ) : (
    <Badge variant="info">作成中</Badge>
  )

  const headerItems = [
    { label: "物件名", value: header.propertyName },
    { label: "所在", value: header.address },
    { label: "部屋番号", value: `${header.roomNumber}号室` },
    { label: "間取り・面積", value: `${header.layout}・${header.area}` },
    { label: "契約種別", value: header.kind },
    { label: "契約日", value: formatDateJa(header.contractDate) },
    { label: "入居予定日", value: formatDateJa(header.moveInDate) },
  ]

  return (
    <main className="mx-auto w-full max-w-5xl px-4 py-6 sm:px-6 sm:py-10">
      {/* ── Page header ─────────────────────────────────────────────── */}
      <div className="flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between">
        <div className="flex min-w-0 flex-col gap-1">
          <div className="flex flex-wrap items-center gap-2">
            <h1 className="text-2xl font-bold tracking-tight">賃貸借契約書 ／ 重要事項説明</h1>
            {statusBadge}
            <CoSignBadge
              value={reiSetsuCoSign}
              signedLabel="重説 2人確認 済"
              pendingLabel="重説 2人確認 要"
            />
          </div>
          <p className="text-sm text-muted-foreground">
            {header.propertyName}　{header.roomNumber}号室　／　{header.kind}　／　契約日{" "}
            {formatDateJa(header.contractDate)}
          </p>
        </div>
        <div className="flex shrink-0 flex-wrap items-center gap-2">
          <Button variant="outline" size="sm" onClick={saveDraft} disabled={executed}>
            <IconDeviceFloppy className="h-4 w-4" aria-hidden="true" />
            下書き保存
          </Button>
          <Button variant="outline" size="sm" onClick={() => window.print()}>
            <IconPrinter className="h-4 w-4" aria-hidden="true" />
            印刷 / PDF
          </Button>
        </div>
      </div>

      {savedAt ? (
        <p className="mt-2 text-xs text-muted-foreground" role="status">
          下書きを保存しました（{formatTimestampJa(savedAt)}）。
        </p>
      ) : null}

      {/* ── Property / contract header summary ─────────────────────── */}
      <Card className="mt-6">
        <CardHeader>
          <div className="flex items-center gap-2">
            <IconBuildingSkyscraper className="h-5 w-5 text-muted-foreground" aria-hidden="true" />
            <CardTitle as="h2">物件・契約ヘッダ</CardTitle>
          </div>
          <CardDescription>対象物件と契約の基本情報。</CardDescription>
        </CardHeader>
        <CardContent>
          <MetadataList layout="horizontal" items={headerItems} />
        </CardContent>
      </Card>

      {/* ── Signed record engine (execute → lock → 覚書) ───────────── */}
      <Card className="mt-6">
        <CardHeader>
          <div className="flex items-center gap-2">
            <IconFileText className="h-5 w-5 text-muted-foreground" aria-hidden="true" />
            <CardTitle as="h2">契約内容</CardTitle>
          </div>
          <CardDescription>
            締結すると契約内容はロックされ、以後の変更は覚書（追記）でのみ行えます。
          </CardDescription>
        </CardHeader>
        <CardContent>
          {!executed && !canExecute ? (
            <Alert variant="warning" className="mb-4">
              <IconAlertTriangle className="h-4 w-4" aria-hidden="true" />
              <AlertTitle as="h3">締結には未完了の項目があります</AlertTitle>
              <AlertDescription>
                <ul className="ml-4 list-disc">
                  {missing.map((m) => (
                    <li key={m}>{m}</li>
                  ))}
                </ul>
              </AlertDescription>
            </Alert>
          ) : null}

          <SignedRecord
            value={record}
            onChange={handleRecordChange}
            signerId={TAKKEN_SHI_ID}
            // SignedRecord's own "sign" button is the single execute control,
            // gated on the FULL legal gate (terms + 重説 + 2人確認 + 当事者).
            // handleRecordChange intercepts the draft→signed transition to also
            // stamp every required party's 記名押印 (SignedRecord records only
            // one signedBy). NOTE: there is no confirm-before-sign hook and no
            // way to require a multi-party signature — see FINDINGS.
            canSign={canExecute}
            requireAddendumReason
            formatTime={formatTimestampJa}
            labels={{
              draft: executed ? "締結済（ロック）" : "下書き（編集可）",
              signed: "締結済（ロック）",
              sign: "契約締結・署名",
              locked: "締結済みの契約は変更できません。変更は覚書（追記）で行います。",
              addendaTitle: "覚書（変更合意の追記）",
              addendum: "覚書を追加",
              addendumBody: "覚書の内容（変更点・新たな合意事項）",
              addendumReason: "覚書の当事者・締結日",
              addendumSubmit: "覚書を締結",
              signedByLabel: "締結（記名）",
            }}
          >
            {({ readOnly }) => (
              <div className="flex flex-col gap-6">
                <ContractBody
                  header={header}
                  setHeader={setHeader}
                  terms={terms}
                  updateTerm={updateTerm}
                  clauses={clauses}
                  addClause={addClause}
                  removeClause={removeClause}
                  updateClause={updateClause}
                  moveClause={moveClause}
                  disclosures={disclosures}
                  toggleDisclosure={toggleDisclosure}
                  lesseeAcknowledged={lesseeAcknowledged}
                  setLesseeAcknowledged={setLesseeAcknowledged}
                  reiSetsuCoSign={reiSetsuCoSign}
                  setReiSetsuCoSign={setReiSetsuCoSign}
                  parties={parties}
                  signParty={signParty}
                  readOnly={readOnly}
                  allDisclosuresConfirmed={allDisclosuresConfirmed}
                />

                {/* Money summary — always visible, reconciles */}
                <ContractSummary
                  terms={terms}
                  monthlyTotal={monthlyTotal}
                  brokerFee={brokerFee}
                  initialCost={initialCost}
                  months={months}
                />

                {/* Execute status. The execute *control* is SignedRecord's own
                    "契約締結・署名" button (top of the record, gated by canSign).
                    Here we surface the gate state + a confirm dialog the user
                    can open to review before using that button. */}
                {!readOnly ? (
                  <div className="flex flex-col gap-2 rounded-lg border border-border bg-muted/30 p-4">
                    <p className="text-sm font-medium">契約の締結</p>
                    <p className="text-xs text-muted-foreground">
                      上部の「契約締結・署名」で締結します。締結すると契約内容はロックされ、
                      宅建士の記名と締結日時が記録されます。
                    </p>
                    <div className="flex flex-wrap items-center gap-2">
                      {canExecute ? (
                        <span className="inline-flex items-center gap-1 text-xs text-success">
                          <IconCircleCheck className="h-3.5 w-3.5" aria-hidden="true" />
                          締結の要件を満たしています。
                        </span>
                      ) : (
                        <span className="inline-flex items-center gap-1 text-xs text-warning">
                          <IconAlertTriangle className="h-3.5 w-3.5" aria-hidden="true" />
                          未完了の項目があるため締結できません。
                        </span>
                      )}
                      <Button
                        type="button"
                        variant="outline"
                        size="sm"
                        onClick={() => setConfirmOpen(true)}
                      >
                        <IconFileText className="h-3.5 w-3.5" aria-hidden="true" />
                        締結前サマリを確認
                      </Button>
                    </div>
                  </div>
                ) : (
                  <ExecutedAudit record={record} parties={parties} />
                )}
              </div>
            )}
          </SignedRecord>
        </CardContent>
      </Card>

      {/* ── 締結前サマリ確認ダイアログ（read-only review） ─────────── */}
      <Dialog open={confirmOpen} onOpenChange={setConfirmOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>締結前サマリ</DialogTitle>
            <DialogDescription>
              締結すると契約内容（条件・特約・重説・当事者）はロックされ、編集できなくなります。
              以後の変更は覚書（追記）でのみ可能です。内容を確認のうえ、上部の「契約締結・署名」で締結してください。
            </DialogDescription>
          </DialogHeader>
          <div className="rounded-md border border-border bg-muted/30 p-3 text-sm">
            <p className="font-medium">{header.propertyName}　{header.roomNumber}号室</p>
            <p className="text-muted-foreground">
              月額 {yen(monthlyTotal)}（賃料 {yen(terms.rent)} ＋ 管理費 {yen(terms.managementFee)}）
              ／ 契約期間 {formatDateJa(terms.termStart)}〜{formatDateJa(terms.termEnd)}
            </p>
            <p className="mt-1 text-muted-foreground">
              締結（記名）予定: {TAKKEN_SHI_ID}
            </p>
          </div>
          <DialogFooter>
            <DialogClose asChild>
              <Button variant="outline">閉じる</Button>
            </DialogClose>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </main>
  )
}

/* ════════════════════════════════════════════════════════════════════════
   Contract body — tabbed: 契約条件 / 特約 / 重要事項説明 / 当事者
   ════════════════════════════════════════════════════════════════════════ */

interface ContractBodyProps {
  header: typeof initialHeader
  setHeader: React.Dispatch<React.SetStateAction<typeof initialHeader>>
  terms: ContractTerms
  updateTerm: <K extends keyof ContractTerms>(key: K, value: ContractTerms[K]) => void
  clauses: SpecialClause[]
  addClause: () => void
  removeClause: (id: string) => void
  updateClause: (id: string, text: string) => void
  moveClause: (id: string, dir: -1 | 1) => void
  disclosures: DisclosureItem[]
  toggleDisclosure: (id: string, on: boolean) => void
  lesseeAcknowledged: boolean
  setLesseeAcknowledged: (v: boolean) => void
  reiSetsuCoSign: CoSignValue | undefined
  setReiSetsuCoSign: (v: CoSignValue) => void
  parties: Party[]
  signParty: (id: string) => void
  readOnly: boolean
  allDisclosuresConfirmed: boolean
}

function ContractBody(props: ContractBodyProps) {
  const {
    header,
    setHeader,
    terms,
    updateTerm,
    clauses,
    addClause,
    removeClause,
    updateClause,
    moveClause,
    disclosures,
    toggleDisclosure,
    lesseeAcknowledged,
    setLesseeAcknowledged,
    reiSetsuCoSign,
    setReiSetsuCoSign,
    parties,
    signParty,
    readOnly,
    allDisclosuresConfirmed,
  } = props

  return (
    <Tabs defaultValue="terms" className="w-full">
      <TabsList className="flex w-full flex-wrap justify-start gap-1">
        <TabsTrigger value="terms">契約条件</TabsTrigger>
        <TabsTrigger value="clauses">特約事項</TabsTrigger>
        <TabsTrigger value="disclosure">重要事項説明</TabsTrigger>
        <TabsTrigger value="parties">当事者・署名</TabsTrigger>
      </TabsList>

      {/* ── 契約条件 ─────────────────────────────────────────────── */}
      <TabsContent value="terms" className="px-0">
        <h3 className="sr-only">契約条件</h3>
        <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
          <MoneyField
            label="賃料（月額）"
            value={terms.rent}
            onValueChange={(v) => updateTerm("rent", v ?? 0)}
            readOnly={readOnly}
          />
          <MoneyField
            label="管理費・共益費（月額）"
            value={terms.managementFee}
            onValueChange={(v) => updateTerm("managementFee", v ?? 0)}
            readOnly={readOnly}
          />
          <MoneyField
            label="敷金"
            value={terms.deposit}
            onValueChange={(v) => updateTerm("deposit", v ?? 0)}
            readOnly={readOnly}
            description="退去時に精算のうえ返還"
          />
          <MoneyField
            label="礼金"
            value={terms.keyMoney}
            onValueChange={(v) => updateTerm("keyMoney", v ?? 0)}
            readOnly={readOnly}
          />
          <Input
            label="契約期間（開始）"
            type="date"
            value={terms.termStart}
            onChange={(e) => updateTerm("termStart", e.target.value)}
            disabled={readOnly}
          />
          <Input
            label="契約期間（満了）"
            type="date"
            value={terms.termEnd}
            onChange={(e) => updateTerm("termEnd", e.target.value)}
            disabled={readOnly}
          />
          <Select
            label="更新区分"
            value={terms.renewalKind}
            onChange={(e) => updateTerm("renewalKind", e.target.value as RenewalKind)}
            disabled={readOnly}
          >
            <option value="自動更新">自動更新</option>
            <option value="合意更新">合意更新</option>
            <option value="更新なし（定期）">更新なし（定期借家）</option>
          </Select>
          <MoneyField
            label="更新料"
            value={terms.renewalFee}
            onValueChange={(v) => updateTerm("renewalFee", v ?? 0)}
            readOnly={readOnly}
          />
          <Select
            label="支払方法"
            value={terms.paymentMethod}
            onChange={(e) => updateTerm("paymentMethod", e.target.value)}
            disabled={readOnly}
          >
            <option value="口座振替">口座振替</option>
            <option value="銀行振込">銀行振込</option>
            <option value="集金代行">集金代行</option>
          </Select>
          <Input
            label="支払日"
            value={terms.paymentDay}
            onChange={(e) => updateTerm("paymentDay", e.target.value)}
            disabled={readOnly}
          />
          <Select
            label="契約種別"
            value={header.kind}
            onChange={(e) => setHeader((h) => ({ ...h, kind: e.target.value as ContractKind }))}
            disabled={readOnly}
          >
            <option value="普通借家">普通借家契約</option>
            <option value="定期借家">定期借家契約</option>
          </Select>
        </div>
      </TabsContent>

      {/* ── 特約事項 ─────────────────────────────────────────────── */}
      <TabsContent value="clauses" className="px-0">
        <div className="mb-3 flex items-center justify-between gap-2">
          <h3 className="text-base font-semibold">特約事項</h3>
          {!readOnly ? (
            <Button size="sm" variant="outline" onClick={addClause}>
              <IconPlus className="h-4 w-4" aria-hidden="true" />
              特約を追加
            </Button>
          ) : null}
        </div>
        {clauses.length === 0 ? (
          <p className="rounded-md border border-dashed p-4 text-sm text-muted-foreground">
            特約はありません。
          </p>
        ) : (
          <ol className="flex flex-col gap-2">
            {clauses.map((c, i) => (
              <li
                key={c.id}
                className="flex items-start gap-2 rounded-lg border border-border bg-card p-3"
              >
                <span
                  className="mt-1.5 inline-flex h-6 w-6 shrink-0 items-center justify-center rounded-full bg-muted text-xs font-semibold text-muted-foreground"
                  aria-hidden="true"
                >
                  {i + 1}
                </span>
                <div className="min-w-0 flex-1">
                  {readOnly ? (
                    <p className="text-sm leading-relaxed">
                      <span className="sr-only">第{i + 1}条　</span>
                      {c.text}
                    </p>
                  ) : (
                    <Textarea
                      aria-label={`特約 第${i + 1}項`}
                      rows={2}
                      value={c.text}
                      placeholder="特約条項を入力（例：ペットの飼育は不可）"
                      onChange={(e) => updateClause(c.id, e.target.value)}
                    />
                  )}
                </div>
                {!readOnly ? (
                  <div className="flex shrink-0 flex-col gap-1">
                    <Button
                      size="icon"
                      variant="ghost"
                      aria-label={`第${i + 1}項を上へ移動`}
                      disabled={i === 0}
                      onClick={() => moveClause(c.id, -1)}
                    >
                      <IconArrowUp className="h-4 w-4" aria-hidden="true" />
                    </Button>
                    <Button
                      size="icon"
                      variant="ghost"
                      aria-label={`第${i + 1}項を下へ移動`}
                      disabled={i === clauses.length - 1}
                      onClick={() => moveClause(c.id, 1)}
                    >
                      <IconArrowDown className="h-4 w-4" aria-hidden="true" />
                    </Button>
                    <Button
                      size="icon"
                      variant="ghost"
                      aria-label={`第${i + 1}項を削除`}
                      onClick={() => removeClause(c.id)}
                    >
                      <IconTrash className="h-4 w-4 text-destructive" aria-hidden="true" />
                    </Button>
                  </div>
                ) : null}
              </li>
            ))}
          </ol>
        )}
      </TabsContent>

      {/* ── 重要事項説明 ─────────────────────────────────────────── */}
      <TabsContent value="disclosure" className="px-0">
        <div className="flex items-center gap-2">
          <IconShieldCheck className="h-5 w-5 text-muted-foreground" aria-hidden="true" />
          <h3 className="text-base font-semibold">重要事項説明（宅建士が説明）</h3>
        </div>
        <p className="mt-1 text-sm text-muted-foreground">
          宅地建物取引士が各項目を説明し、確認のうえチェックします。借主は説明を受領したことを確認します。
        </p>

        <ul className="mt-4 flex flex-col gap-3">
          {disclosures.map((d) => (
            <li key={d.id} className="rounded-lg border border-border bg-card p-4">
              <div className="flex items-start justify-between gap-3">
                <div className="min-w-0">
                  <p className="text-sm font-semibold">{d.title}</p>
                  <p className="mt-1 text-sm leading-relaxed text-muted-foreground">{d.detail}</p>
                </div>
                {d.confirmed ? (
                  <Badge variant="success">確認済</Badge>
                ) : (
                  <Badge variant="warning">未確認</Badge>
                )}
              </div>
              <div className="mt-3">
                <Checkbox
                  checked={d.confirmed}
                  disabled={readOnly}
                  onCheckedChange={(on) => toggleDisclosure(d.id, on)}
                  label={`「${d.title}」を説明し、確認しました（宅建士）`}
                />
              </div>
            </li>
          ))}
        </ul>

        <Separator className="my-5" />

        {/* 借主の受領確認 + 宅建士・借主の相互確認(2人確認) */}
        <div className="flex flex-col gap-4 rounded-lg border border-border bg-muted/20 p-4">
          <div>
            <p className="text-sm font-semibold">借主の受領確認</p>
            <div className="mt-2">
              <Checkbox
                checked={lesseeAcknowledged}
                disabled={readOnly || !allDisclosuresConfirmed}
                onCheckedChange={setLesseeAcknowledged}
                label="借主は、宅地建物取引士から重要事項説明（書面）を受け、その内容を確認しました。"
                description={
                  allDisclosuresConfirmed
                    ? undefined
                    : "全ての重説項目の確認後に有効化されます。"
                }
              />
            </div>
          </div>

          <Separator />

          <div>
            <div className="flex items-center justify-between gap-2">
              <p className="text-sm font-semibold">重説の相互確認（宅建士 ↔ 借主）</p>
              <CoSignBadge value={reiSetsuCoSign} signedLabel="2人確認 済" pendingLabel="2人確認 要" />
            </div>
            <p className="mt-1 text-xs text-muted-foreground">
              説明を行った宅建士（{TAKKEN_SHI_ID}）に対し、説明を受けた借主が確認者として署名します。
            </p>
            <div className="mt-3">
              {readOnly && !reiSetsuCoSign ? (
                <p className="text-xs text-muted-foreground">締結済みのため確認できません。</p>
              ) : (
                <CoSign
                  primaryId={TAKKEN_SHI_ID}
                  value={reiSetsuCoSign}
                  onSign={setReiSetsuCoSign}
                  requireReason={false}
                  signerLabel="確認者（借主）の氏名"
                  attestations={[
                    {
                      id: "att-received",
                      label: "重要事項説明書の交付・説明を受けました。",
                    },
                    {
                      id: "att-understood",
                      label: "記載内容（権利関係・法令制限・解除事由・敷金精算）を理解しました。",
                    },
                  ]}
                  labels={{
                    sign: "借主として確認・署名",
                    signed: "重説 2人確認 済",
                    signerOf: (id) => `確認者（借主）: ${id}`,
                  }}
                />
              )}
            </div>
          </div>
        </div>
      </TabsContent>

      {/* ── 当事者・署名 ─────────────────────────────────────────── */}
      <TabsContent value="parties" className="px-0">
        <div className="flex items-center gap-2">
          <IconUsers className="h-5 w-5 text-muted-foreground" aria-hidden="true" />
          <h3 className="text-base font-semibold">当事者（記名押印 / 署名）</h3>
        </div>
        <p className="mt-1 text-sm text-muted-foreground">
          各当事者の記名押印・署名を記録します。宅建士の記名押印は法令上必須です。
        </p>

        <div className="mt-4 hidden overflow-x-auto sm:block">
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>区分</TableHead>
                <TableHead>氏名・名称</TableHead>
                <TableHead>詳細</TableHead>
                <TableHead className="text-center">署名・記名押印</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {parties.map((p) => (
                <TableRow key={p.id}>
                  <TableCell className="whitespace-nowrap align-top font-medium">
                    {p.role}
                    {p.required ? <span className="ml-1 text-destructive" aria-hidden="true">*</span> : null}
                  </TableCell>
                  <TableCell className="align-top">{p.name}</TableCell>
                  <TableCell className="align-top text-xs text-muted-foreground">{p.detail}</TableCell>
                  <TableCell className="align-top text-center">
                    <PartySign party={p} onSign={() => signParty(p.id)} readOnly={readOnly} />
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </div>

        {/* mobile: stacked cards (375px) */}
        <ul className="mt-4 flex flex-col gap-3 sm:hidden">
          {parties.map((p) => (
            <li key={p.id} className="rounded-lg border border-border bg-card p-3">
              <div className="flex items-center justify-between gap-2">
                <span className="text-sm font-semibold">
                  {p.role}
                  {p.required ? <span className="ml-1 text-destructive" aria-hidden="true">*</span> : null}
                </span>
                <PartySign party={p} onSign={() => signParty(p.id)} readOnly={readOnly} />
              </div>
              <p className="mt-1 text-sm">{p.name}</p>
              <p className="mt-0.5 text-xs text-muted-foreground">{p.detail}</p>
            </li>
          ))}
        </ul>
        <p className="mt-2 text-xs text-muted-foreground">
          <span className="text-destructive">*</span> 必須当事者
        </p>
      </TabsContent>
    </Tabs>
  )
}

/* ════════════════════════════════════════════════════════════════════════
   Small composed helpers
   ════════════════════════════════════════════════════════════════════════ */

function MoneyField({
  label,
  value,
  onValueChange,
  readOnly,
  description,
}: {
  label: string
  value: number
  onValueChange: (v: number | undefined) => void
  readOnly: boolean
  description?: string
}) {
  const reactId = React.useId()
  const id = `${reactId}-money`
  const descId = description ? `${reactId}-desc` : undefined
  return (
    <div className="flex w-full flex-col gap-1.5">
      <label htmlFor={id} className="text-sm font-medium leading-none text-foreground">
        {label}
      </label>
      {readOnly ? (
        <p id={id} className="inline-flex h-9 items-center rounded-lg border border-input bg-muted/40 px-3 text-sm font-medium tabular-nums">
          {yen(value)}
        </p>
      ) : (
        <CurrencyInput
          id={id}
          value={value}
          min={0}
          onValueChange={onValueChange}
          aria-describedby={descId}
          className="inline-flex h-9 w-full items-center rounded-lg border border-input bg-transparent px-3 py-2 text-right text-sm tabular-nums shadow-sm focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring"
        />
      )}
      {description ? (
        <p id={descId} className="text-xs text-muted-foreground">
          {description}
        </p>
      ) : null}
    </div>
  )
}

function PartySign({
  party,
  onSign,
  readOnly,
}: {
  party: Party
  onSign: () => void
  readOnly: boolean
}) {
  if (party.signedAt) {
    return (
      <span className="inline-flex flex-col items-center gap-0.5">
        <Badge variant="success">署名済</Badge>
        <span className="text-[11px] text-muted-foreground tabular-nums">
          {formatTimestampJa(party.signedAt)}
        </span>
      </span>
    )
  }
  if (readOnly) {
    return <Badge variant="warning">未署名</Badge>
  }
  return (
    <Button size="sm" variant="outline" onClick={onSign}>
      <IconRubberStamp className="h-3.5 w-3.5" aria-hidden="true" />
      署名
    </Button>
  )
}

function ContractSummary({
  terms,
  monthlyTotal,
  brokerFee,
  initialCost,
  months,
}: {
  terms: ContractTerms
  monthlyTotal: number
  brokerFee: number
  initialCost: number
  months: number | null
}) {
  const items = [
    { label: "月額合計（賃料＋管理費）", value: yen(monthlyTotal) },
    { label: "敷金", value: yen(terms.deposit) },
    { label: "礼金", value: yen(terms.keyMoney) },
    { label: "仲介手数料（賃料1ヶ月＋税）", value: yen(brokerFee) },
    { label: "初月賃料（管理費込）", value: yen(monthlyTotal) },
    { label: "契約時初期費用 合計", value: yen(initialCost) },
    { label: "契約期間", value: months ? `${months}ヶ月` : "—" },
    { label: "更新料", value: yen(terms.renewalFee) },
  ]
  return (
    <section aria-labelledby="summary-heading" className="rounded-lg border border-border bg-muted/20 p-4">
      <h3 id="summary-heading" className="mb-3 text-sm font-semibold">
        契約サマリ（金額の照合）
      </h3>
      <MetadataList layout="horizontal" items={items} />
    </section>
  )
}

function ExecutedAudit({
  record,
  parties,
}: {
  record: SignedRecordValue
  parties: Party[]
}) {
  return (
    <Alert variant="success">
      <IconCircleCheck className="h-4 w-4" aria-hidden="true" />
      <AlertTitle as="h3">本契約は締結済みです</AlertTitle>
      <AlertDescription>
        <p>
          締結（宅建士記名）: {record.signedBy} ／{" "}
          {record.signedAt ? formatTimestampJa(record.signedAt) : "—"}
        </p>
        <p className="mt-1">
          署名済当事者:{" "}
          {parties
            .filter((p) => p.signedAt)
            .map((p) => `${p.role}（${p.name}）`)
            .join("、 ") || "—"}
        </p>
        <p className="mt-1 text-muted-foreground">
          内容の変更は上部の「覚書を追加」から、変更点・当事者・締結日を記して追記してください。
        </p>
      </AlertDescription>
    </Alert>
  )
}
